 41	//------------------------------------------------------------------------------
 42	int rrc_eNB_compare_ue_rnti_id(
 43	  struct rrc_eNB_ue_context_s *c1_pP, struct rrc_eNB_ue_context_s *c2_pP)
 44	//------------------------------------------------------------------------------
 45	{
 46	  if (c1_pP->ue_id_rnti > c2_pP->ue_id_rnti) {
 47	    return 1;
 48	  }
 49	
 50	  if (c1_pP->ue_id_rnti < c2_pP->ue_id_rnti) {
 51	    return -1;
 52	  }
 53	
 54	  return 0;
 55	}
 56	
 57	/* Generate the tree management functions */
 58	RB_GENERATE(rrc_ue_tree_s, rrc_eNB_ue_context_s, entries,
 59	            rrc_eNB_compare_ue_rnti_id);
