149	          PROTOCOL_RRC_CTXT_UE_ARGS(ctxt_pP));
150	    return;
151	  }
152	
153	  RB_REMOVE(rrc_ue_tree_s, &rrc_instance_pP->rrc_ue_head, ue_context_pP);
