156	  free(ue_context_pP);
157	  rrc_instance_pP->Nb_ue --;
158	  LOG_I(RRC,
159	        PROTOCOL_RRC_CTXT_UE_FMT" Removed UE context\n",
160	        PROTOCOL_RRC_CTXT_UE_ARGS(ctxt_pP));
161	}
